-- Step 1: Add role column to users table with the 4-tier hierarchy
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'users' AND column_name = 'role'
  ) THEN
    ALTER TABLE users ADD COLUMN role TEXT NOT NULL DEFAULT 'agent'
      CHECK (role IN ('super_admin', 'nvc_manager', 'merchant_manager', 'agent'));
  END IF;
END $$;

-- Step 2: Add is_nvc_platform flag to tenants table
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'tenants' AND column_name = 'is_nvc_platform'
  ) THEN
    ALTER TABLE tenants ADD COLUMN is_nvc_platform BOOLEAN NOT NULL DEFAULT FALSE;
  END IF;
END $$;

-- Step 3: Add suspended flag to tenants table
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'tenants' AND column_name = 'suspended'
  ) THEN
    ALTER TABLE tenants ADD COLUMN suspended BOOLEAN NOT NULL DEFAULT FALSE;
  END IF;
END $$;

-- Step 4: Create merchant_settings table
CREATE TABLE IF NOT EXISTS merchant_settings (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  tenant_id UUID NOT NULL UNIQUE,
  preferences JSONB NOT NULL DEFAULT '{}',
  theme JSONB NOT NULL DEFAULT '{}',
  notifications JSONB NOT NULL DEFAULT '{}',
  sms_config JSONB NOT NULL DEFAULT '{}',
  email_config JSONB NOT NULL DEFAULT '{}',
  templates JSONB NOT NULL DEFAULT '{}',
  auto_allocation BOOLEAN NOT NULL DEFAULT FALSE,
  updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL
);

-- Step 5: Create user_merchant_access join table (NVC staff → merchant tenant access)
CREATE TABLE IF NOT EXISTS user_merchant_access (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL,
  tenant_id UUID NOT NULL,
  granted_by UUID NOT NULL,
  granted_at TIMESTAMPTZ DEFAULT NOW() NOT NULL,
  UNIQUE(user_id, tenant_id)
);

-- Step 6: Create indexes for performance
CREATE INDEX IF NOT EXISTS idx_users_role ON users(role);
CREATE INDEX IF NOT EXISTS idx_tenants_is_nvc_platform ON tenants(is_nvc_platform);
CREATE INDEX IF NOT EXISTS idx_tenants_suspended ON tenants(suspended);
CREATE INDEX IF NOT EXISTS idx_merchant_settings_tenant ON merchant_settings(tenant_id);
CREATE INDEX IF NOT EXISTS idx_user_merchant_access_user ON user_merchant_access(user_id);
CREATE INDEX IF NOT EXISTS idx_user_merchant_access_tenant ON user_merchant_access(tenant_id);

